// Scoped IPC for the proactive-assistant settings the Notifications tab (and, in a
// later PR, the General "Screen Analysis" row) drive. A deliberately small,
// WHITELISTED bridge over the central app-settings store — NOT a generic
// appSettings pass-through: the renderer may read/write ONLY these flags, so it can
// never reach an unrelated key (recordHotkey, goalAutoGeneratedIds, …) through this
// channel. Mirrors the codebase's scoped-IPC convention (chatPrivacy.ts,
// meeting.ts, goals/register.ts) rather than exposing setAppSettings directly.
//
// Writing the setting is the whole action: the proactive coordinator re-syncs on
// any settings write (coordinator.ts onAppSettingsChanged), and the tray checkbox
// already syncs, so a Settings toggle needs no extra start/stop call here. We
// additionally BROADCAST the fresh projection so every open window's Settings rows
// stay in lock-step when the same flag is written elsewhere (the tray "Screen
// Analysis" checkbox, a future backend sync) — the two can never disagree.
import { BrowserWindow, ipcMain } from 'electron'
import { is } from '@electron-toolkit/utils'
import { getAppSettings, setAppSettings, onAppSettingsChanged } from '../appSettings'
import type { AppSettings } from '../appSettings'
import { notifyProactive } from '../assistants/core/notify'
import type { AssistantSettingsView, InsightPayload } from '../../shared/types'

// The exact keys the renderer may write through this channel. Anything else in a
// patch is dropped BEFORE it reaches setAppSettings (see filterAssistantPatch).
// Kept as a `satisfies` list so a typo can't add a key that isn't a real setting.
const WRITABLE_KEYS = [
  'notificationsEnabled',
  'notificationFrequency',
  'focusNotificationsEnabled',
  'memoryEnabled',
  'glowOverlayEnabled',
  'screenAnalysisEnabled'
] as const satisfies readonly (keyof AppSettings)[]

export type AssistantWritableKey = (typeof WRITABLE_KEYS)[number]

/** Project the full settings down to the assistant-facing view the renderer sees. */
export function projectAssistantSettings(): AssistantSettingsView {
  const s = getAppSettings()
  return {
    notificationsEnabled: s.notificationsEnabled,
    notificationFrequency: s.notificationFrequency,
    focusNotificationsEnabled: s.focusNotificationsEnabled,
    memoryEnabled: s.memoryEnabled,
    glowOverlayEnabled: s.glowOverlayEnabled,
    screenAnalysisEnabled: s.screenAnalysisEnabled
  }
}

/** Keep only the whitelisted KEYS from an untrusted renderer patch. The values
 *  stay untrusted: sanitizeAppSettings (run inside setAppSettings) is what coerces
 *  a junk frequency to 0, a non-boolean toggle to its default, etc. This step is
 *  purely about which keys may be written, never their validity. */
export function filterAssistantPatch(
  patch: unknown
): Partial<Pick<AppSettings, AssistantWritableKey>> {
  const out: Partial<Pick<AppSettings, AssistantWritableKey>> = {}
  if (!patch || typeof patch !== 'object') return out
  const src = patch as Record<string, unknown>
  for (const k of WRITABLE_KEYS) {
    if (Object.prototype.hasOwnProperty.call(src, k)) {
      ;(out as Record<string, unknown>)[k] = src[k]
    }
  }
  return out
}

let registered = false

export function registerAssistantSettingsHandlers(): void {
  if (registered) return
  registered = true

  ipcMain.handle('assistants:getSettings', (): AssistantSettingsView => projectAssistantSettings())

  ipcMain.handle('assistants:setSettings', (_e, patch: unknown): AssistantSettingsView => {
    setAppSettings(filterAssistantPatch(patch))
    return projectAssistantSettings()
  })

  // Broadcast every settings write to all windows so a Settings row re-renders when
  // the same flag is written from the tray checkbox or a background sync. Subscribed
  // once (guarded by `registered`); listeners must not throw.
  onAppSettingsChanged(() => {
    const view = projectAssistantSettings()
    for (const w of BrowserWindow.getAllWindows()) {
      if (!w.isDestroyed()) w.webContents.send('assistants:settingsChanged', view)
    }
  })

  if (is.dev) {
    // Dev/QA only: push one proactive notification through the REAL throttle
    // (notifyProactive) and return whether it was delivered. Proves the frequency /
    // master gates end to end — false at stock (frequency Off), true after the UI
    // raises the frequency. Never present on shipped builds.
    ipcMain.handle('assistants:debugNotify', (): boolean => {
      const payload: InsightPayload = {
        headline: 'Debug notification',
        advice: 'This is a developer test of the proactive notification path.',
        reasoning: 'assistants:debugNotify',
        category: 'other',
        sourceApp: 'Omi',
        confidence: 1
      }
      return notifyProactive('assistants-debug', payload)
    })
  }
}

/** Test-only: drop the registration guard so a suite can re-register handlers. */
export function _resetAssistantSettingsForTests(): void {
  registered = false
}
